def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 4):
                for b in range(1, 4):
                    score += (np.sin(ratio * a * np.pi) * np.cos(ratio * b * np.pi)) * (a + b)
            score += (1 - ratio)**4 * 25
            if capacity % 4 == 0:
                score += np.log1p(capacity) * 3
        elif 0.2 <= ratio < 0.5:
            score += np.exp(-ratio * 4) * 20
            for k in range(1, int(capacity)+1):
                if capacity % k == 0 and k % 3 == 0 and k < item * 2:
                    score += k * 0.15
            if int(capacity) % 7 == 0:
                score -= 5
        elif 0.5 <= ratio < 0.75:
            base = ratio ** 3 * 30
            score += base
            for x in range(1, 6):
                if x % 2 == 0:
                    score += np.sin(ratio * x * 2 * np.pi) * (x * 2)
                else:
                    score -= np.cos(ratio * x * np.pi) * x
            if np.isclose(ratio, 0.6, atol=0.05):
                score *= 1.2
            for d in range(1, int(capacity // 3) + 1):
                if capacity % d == 0:
                    score += np.sqrt(d) * 0.7
        elif 0.75 <= ratio <= 1:
            sigmoid = 1 / (1 + np.exp(-15 * (ratio - 0.9)))
            score += sigmoid * 40
            for f in range(1, 8):
                score += ((-1) ** f) * np.log1p(ratio * f) * (f + 1)
            if capacity % 6 == 0:
                score *= 0.85
        elif 1 < ratio < 1.5:
            penalty = 0
            int_ratio = int(np.floor(ratio))
            for m in range(1, int_ratio + 2):
                if int_ratio % m == 0 or m == int_ratio + 1:
                    penalty += m * 1.5
                else:
                    penalty -= m * 0.5
            score = penalty + (ratio - 1) * 40
            for n in range(1, 5):
                score -= np.tanh(ratio / n) * 4
            if capacity % 8 == 0 and ratio > 1.2:
                score += 10
        else:
            penalty = 0
            int_ratio = int(np.ceil(ratio))
            for p in range(1, int_ratio + 3):
                if p % 2 == 0:
                    penalty += np.log1p(p * ratio) * p
                else:
                    penalty -= np.sqrt(p + ratio) * (p / 2)
                if p == int_ratio:
                    penalty += (p ** 2) * 0.05
            score = penalty + (ratio - 1.4) * 50
            for q in range(1, 7):
                if capacity % q == 0:
                    score -= np.exp(-q/2) * 3
            if ratio > 3:
                score += np.log1p(ratio) * 20
        if int(capacity) % 9 == 0 and 0.3 < ratio < 0.8:
            score *= 1.15
        if capacity % 5 == 0 and ratio > 1.2:
            score *= 0.9
        if int(capacity) % 11 == 0:
            score += np.sin(ratio * np.pi * 3) * 7
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 250)
    return priorities
